import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useNavigate } from "react-router-dom";

export default function EditProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [name, setName] = useState("");

  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  // ✅ LOAD PROFILE
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("user") || "{}");

    if (!stored?.email) {
      navigate("/");
      return;
    }

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      })
      .catch((err) => {
        console.log(err);
        Swal.fire("Error", "Failed to load profile", "error");
      });
  }, [navigate]);

  // ✅ IMAGE PREVIEW
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    const reader = new FileReader();
    reader.onloadend = () => {
      setPreview(reader.result);
    };
    reader.readAsDataURL(file);
  };

  // ✅ UPDATE PROFILE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);

      if (imageFile) {
        formData.append("image", imageFile);
      }

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData
      );

      // ✅ backend returns USER object (NOT message)
      Swal.fire("Success", "Profile updated successfully", "success");

      // ✅ sync localStorage with backend
      localStorage.setItem("user", JSON.stringify(res.data));

      navigate("/profile");
    } catch (err) {
      console.log(err);
      Swal.fire(
        "Error",
        err.response?.data?.message || "Update failed",
        "error"
      );
    }
  };

  // ✅ CHANGE PASSWORD
  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");

      setCurrentPassword("");
      setNewPassword("");
    } catch (err) {
      Swal.fire(
        "Error",
        err.response?.data?.message || "Password update failed",
        "error"
      );
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        Loading profile...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex justify-center p-6">
      <div className="bg-white p-6 rounded-xl shadow w-full max-w-lg">

        <h2 className="text-xl font-bold mb-4">Edit Profile</h2>

        {/* NAME */}
        <input
          className="w-full border p-2 mb-3 rounded"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />

        {/* IMAGE */}
        <input
          type="file"
          accept="image/*"
          onChange={handleImageChange}
          className="w-full mb-3"
        />

        {/* PREVIEW */}
        <img
          src={
            preview ||
            `https://ui-avatars.com/api/?name=${user.username}`
          }
          alt="preview"
          className="w-24 h-24 rounded-full mx-auto mb-4 object-cover"
        />

        {/* SAVE */}
        <button
          onClick={handleUpdateProfile}
          className="w-full bg-green-600 text-white py-2 rounded mb-6"
        >
          Save Changes
        </button>

        <hr className="my-4" />

        {/* PASSWORD */}
        <input
          type="password"
          placeholder="Current Password"
          className="w-full border p-2 mb-2 rounded"
          value={currentPassword}
          onChange={(e) => setCurrentPassword(e.target.value)}
        />

        <input
          type="password"
          placeholder="New Password"
          className="w-full border p-2 mb-3 rounded"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
        />

        <button
          onClick={handleChangePassword}
          className="w-full bg-indigo-600 text-white py-2 rounded"
        >
          Change Password
        </button>

      </div>
    </div>
  );
}
